async function run(input) {
  var md = String((input && input.markdown) || '');
  var output = String((input && input.output) || 'html').toLowerCase();
  function escapeHtml(s) {
    return s.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');
  }
  function inline(s) {
    s = escapeHtml(s);
    s = s.replace(/`([^`]+)`/g, '<code>$1</code>');
    s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');
    s = s.replace(/\*\*([^*]+)\*\*/g, '<strong>$1</strong>');
    s = s.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    return s;
  }
  var lines = md.replace(/\r\n/g, '\n').split('\n');
  if (output === 'text') {
    var out = [];
    for (var i = 0; i < lines.length; i++) {
      var t = lines[i];
      t = t.replace(/^\s{0,3}#{1,6}\s+/, '');
      t = t.replace(/^\s*[-*+]\s+/, '');
      t = t.replace(/`([^`]+)`/g, '$1');
      t = t.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '$1');
      t = t.replace(/\*\*([^*]+)\*\*/g, '$1');
      t = t.replace(/\*([^*]+)\*/g, '$1');
      out.push(t);
    }
    var text = out.join('\n').replace(/\n{3,}/g, '\n\n').trim();
    return { output: 'text', ergebnis: text };
  }
  var html = [];
  var inList = false;
  var para = [];
  function flushPara() {
    if (para.length) { html.push('<p>' + inline(para.join(' ')) + '</p>'); para = []; }
  }
  function flushList() {
    if (inList) { html.push('</ul>'); inList = false; }
  }
  for (var j = 0; j < lines.length; j++) {
    var line = lines[j];
    var h = line.match(/^\s{0,3}(#{1,6})\s+(.*)$/);
    var li = line.match(/^\s*[-*+]\s+(.*)$/);
    if (h) {
      flushPara(); flushList();
      var lvl = h[1].length;
      html.push('<h' + lvl + '>' + inline(h[2]) + '</h' + lvl + '>');
    } else if (li) {
      flushPara();
      if (!inList) { html.push('<ul>'); inList = true; }
      html.push('<li>' + inline(li[1]) + '</li>');
    } else if (line.trim() === '') {
      flushPara(); flushList();
    } else {
      flushList();
      para.push(line.trim());
    }
  }
  flushPara(); flushList();
  return { output: 'html', ergebnis: html.join('\n') };
}
